const body = $input.first().json;
const body2 = body.body || body;

const project_id = body2.project_id || null;
const gate_name = body2.gate_name || 'pre-deploy';
const checked_by = body2.checked_by || 'g6-governance-orchestrator';

if (!project_id && !gate_name) {
  throw new Error('release_gate event requires project_id or gate_name');
}

return [{ json: { project_id, gate_name, checked_by, received_at: new Date().toISOString() } }];

// Aggregate all check results
const p0Result = $('Check A: Open P0 Incidents').first().json;
const p1Result = $('Check B: Open P1 Incidents').first().json;
const commitResult = $('Check C: Recent Commit Failures').first().json;

const p0Incidents = (p0Result.data || p0Result || []);
const p0Count = Array.isArray(p0Incidents) ? p0Incidents.length : 0;

const p1Incidents = (p1Result.data || p1Result || []);
const p1Count = Array.isArray(p1Incidents) ? p1Incidents.length : 0;

const commitEvents = (commitResult.data || commitResult || []);
const cutoff7d = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const recentCommitFailures = Array.isArray(commitEvents)
  ? commitEvents.filter(e => { try { return new Date(e.created_at) > cutoff7d; } catch { return false; } })
  : [];
const commitFailCount = recentCommitFailures.length;

const checks = {
  check_a_no_p0_incidents: { passed: p0Count === 0, detail: `Open P0 incidents: ${p0Count}` },
  check_b_no_p1_incidents: { passed: p1Count === 0, detail: `Open P1 incidents: ${p1Count}` },
  check_c_commit_failures: { passed: commitFailCount < 5, detail: `Commit failures (7d): ${commitFailCount} (threshold: 5)` }
};

const criticalFailed = !checks.check_a_no_p0_incidents.passed || !checks.check_b_no_p1_incidents.passed;
const warningFailed = !checks.check_c_commit_failures.passed;

let gate_status = 'passed';
if (criticalFailed) gate_status = 'failed';
else if (warningFailed) gate_status = 'pending';

const evidence = Object.entries(checks)
  .map(([k, v]) => `${v.passed ? 'PASS' : 'FAIL'} ${k}: ${v.detail}`)
  .join('; ');

return [{
  json: {
    gate_status,
    evidence_summary: evidence,
    checks,
    project_id: $('Validate Event').first().json.project_id,
    gate_name: $('Validate Event').first().json.gate_name,
    checked_by: $('Validate Event').first().json.checked_by
  }
}];
